insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:g-4-talking-about-the-past:tf:647ff495', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tf', 'tf', 1, '{"question": "''ayer'' is a time marker usually paired with the preterite."}'::jsonb, '{"answer": true, "explain": "ayer, el año pasado, anoche all point to a finished one-off action → preterite."}'::jsonb),
('spanish:g-4-talking-about-the-past:tf:c5c08fe2', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tf', 'tf', 1, '{"question": "''normalmente'' usually signals the imperfect tense."}'::jsonb, '{"answer": true, "explain": "normalmente, todos los días, de pequeño all point to a habit → imperfect."}'::jsonb),
('spanish:g-4-talking-about-the-past:tf:d53a7d9a', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tf', 'tf', 1, '{"question": "The perfect tense is formed with estar plus a gerund."}'::jsonb, '{"answer": false, "explain": "The perfect is haber + past participle (he comido); estar + gerund (-ando/-iendo) builds the continuous instead."}'::jsonb),
('spanish:g-4-talking-about-the-past:tf:306b6f1b', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tf', 'tf', 1, '{"question": "''tenía'' can mean both ''I had'' and ''he/she had'' in the imperfect."}'::jsonb, '{"answer": true, "explain": "yo and él/ella share identical -ER/-IR imperfect endings: tenía serves both — only context (or a subject pronoun) tells you which."}'::jsonb),
('spanish:g-4-talking-about-the-past:tf:571d8435', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tf', 'tf', 1, '{"question": "''dar'' takes accented endings in the preterite, just like ''hablar'' does."}'::jsonb, '{"answer": false, "explain": "dar borrows the -ER/-IR preterite endings with NO written accents: di, diste, dio, dimos, disteis, dieron."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:288b4e32', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "How do I form the preterite of regular -AR verbs?", "reading": "<p>The preterite (<span data-say=\"el pretérito\">el pretérito</span>) describes a <strong>completed action in the past</strong> — something that happened and finished at a specific point in time.</p>\n            <p>Regular <strong>-AR</strong> verbs like <span data-say=\"hablar\">hablar</span> (to speak) follow this pattern:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"hablé\">hablé</span></td><td>nosotros/as</td><td>hablamos</td></tr>\n              <tr><td>tú</td><td>hablaste</td><td>vosotros/as</td><td>hablasteis</td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"habló\">habló</span></td><td>ellos/ellas/ustedes</td><td>hablaron</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Ayer hablé con mi profesora por teléfono.\">Ayer hablé con mi profesora por teléfono.</span> — <em>Yesterday I spoke to my teacher on the phone.</em> Note the accent on <strong>hablé</strong> and <strong>habló</strong> — without it, the meaning changes!</p>", "question": "What is the ''yo'' (I) form of ''hablar'' in the preterite?", "options": ["hablé", "hablaba", "hablo", "he hablado"]}'::jsonb, '{"answer": 0, "explain": "The ''yo'' preterite ending for -AR verbs is -é (with an accent): hablé. ''hablaba'' is imperfect, ''hablo'' is present, ''he hablado'' is perfect."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:5c7e3396', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "How do I form the preterite of regular -ER/-IR verbs?", "reading": "<p><strong>-ER</strong> and <strong>-IR</strong> verbs share the SAME preterite endings. Compare <span data-say=\"comer\">comer</span> (to eat) and <span data-say=\"vivir\">vivir</span> (to live):</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"comí\">comí</span></td><td><span data-say=\"viví\">viví</span></td></tr>\n              <tr><td>tú</td><td>comiste</td><td>viviste</td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"comió\">comió</span></td><td><span data-say=\"vivió\">vivió</span></td></tr>\n              <tr><td>nosotros/as</td><td>comimos</td><td>vivimos</td></tr>\n              <tr><td>ellos/ellas/ustedes</td><td>comieron</td><td>vivieron</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Anoche comimos pasta en el restaurante.\">Anoche comimos pasta en el restaurante.</span> — <em>Last night we ate pasta at the restaurant.</em></p>", "question": "Which ending do -ER and -IR verbs share for ''él/ella'' in the preterite?", "options": ["-ió (comió, vivió)", "-aba, used for every single verb", "-ía, with no exceptions at all", "-ando, added to the stem"]}'::jsonb, '{"answer": 0, "explain": "-ER/-IR verbs share preterite endings: comió, vivió both end in -ió. -aba/-ía are imperfect endings; -ando builds the gerund."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:5625c62c', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "What are the key irregular preterites?", "reading": "<p>Some very common verbs are IRREGULAR in the preterite — they use different stems and take NO written accent.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"ser\">ser</span> / <span data-say=\"ir\">ir</span></td><td><span data-say=\"fui\">fui</span>, fuiste, <span data-say=\"fue\">fue</span>, fuimos, fuisteis, fueron</td></tr>\n              <tr><td><span data-say=\"hacer\">hacer</span></td><td><span data-say=\"hice\">hice</span>, hiciste, hizo, hicimos</td></tr>\n              <tr><td><span data-say=\"tener\">tener</span></td><td><span data-say=\"tuve\">tuve</span>, tuviste, tuvo, tuvimos</td></tr>\n              <tr><td><span data-say=\"estar\">estar</span></td><td><span data-say=\"estuve\">estuve</span>, estuviste, estuvo, estuvimos</td></tr>\n            </table>\n            <p><strong>ser and ir share IDENTICAL forms</strong> in the preterite — only context tells you which one is meant: <span data-say=\"Fui al cine.\">Fui al cine.</span> (I went) vs <span data-say=\"Fue muy interesante.\">Fue muy interesante.</span> (It was).</p>\n            <p>More irregular preterite stems worth learning: <span data-say=\"decir\">decir</span> → <span data-say=\"dije\">dije</span>, dijiste, dijo, dijimos, dijisteis, dijeron; <span data-say=\"poder\">poder</span> → <span data-say=\"pude\">pude</span>, pudiste, pudo, pudimos; <span data-say=\"saber\">saber</span> → <span data-say=\"supe\">supe</span>, supiste, supo, supimos; <span data-say=\"querer\">querer</span> → <span data-say=\"quise\">quise</span>, quisiste, quiso, quisimos; <span data-say=\"venir\">venir</span> → <span data-say=\"vine\">vine</span>, viniste, vino, vinimos; <span data-say=\"traer\">traer</span> → <span data-say=\"traje\">traje</span>, trajiste, trajo, trajimos, trajisteis, trajeron.</p>\n            <p>Watch the spelling: verbs with a <strong>-j-</strong> stem (decir, traer, and similar verbs) DROP the <strong>i</strong> in the ellos/ellas ending — <span data-say=\"dijeron\">dijeron</span> and <span data-say=\"trajeron\">trajeron</span>, never \"dijieron\"/\"trajieron\".</p>", "question": "''fui'' can mean ''I went'' OR ''I was'', because…", "options": ["ser and ir share identical preterite forms", "the word changes its spelling with meaning", "''fui'' only ever means ''I was'' in context", "''fui'' is a completely regular -IR verb"]}'::jsonb, '{"answer": 0, "explain": "ser (to be) and ir (to go) have exactly the same irregular preterite forms — fui, fuiste, fue… Context tells you which verb is meant."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:7f5fd72c', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "How do I form the imperfect tense?", "reading": "<p>The imperfect (<span data-say=\"el imperfecto\">el imperfecto</span>) describes what you <strong>used to do</strong>, <strong>was doing</strong>, or how things <strong>were</strong> — no fixed end point.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td><span data-say=\"hablaba\">hablaba</span></td><td><span data-say=\"comía\">comía</span></td><td><span data-say=\"vivía\">vivía</span></td></tr>\n              <tr><td>tú</td><td>hablabas</td><td>comías</td><td>vivías</td></tr>\n              <tr><td>él/ella</td><td>hablaba</td><td>comía</td><td>vivía</td></tr>\n              <tr><td>nosotros/as</td><td><span data-say=\"hablábamos\">hablábamos</span></td><td>comíamos</td><td>vivíamos</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Cuando era niño, jugaba al fútbol todos los días.\">Cuando era niño, jugaba al fútbol todos los días.</span> — <em>When I was a child, I used to play football every day.</em></p>", "question": "What does the imperfect tense express?", "options": ["a habitual or ongoing past action (''used to'')", "a single action completed at one exact moment", "an action that is going to happen soon", "an instruction telling someone what to do"]}'::jsonb, '{"answer": 0, "explain": "The imperfect describes habits, ongoing states or descriptions in the past — ''used to'' / ''was -ing''. A single finished action needs the preterite instead."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:5cb2d830', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "Preterite or imperfect — which do I choose?", "reading": "<p>Ask: is it a SINGLE completed event, or a HABIT / DESCRIPTION / ongoing background action?</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><strong>PRETERITE</strong> — one-off, finished</td><td><span data-say=\"ayer\">ayer</span>, <span data-say=\"el año pasado\">el año pasado</span>, <span data-say=\"el fin de semana pasado\">el fin de semana pasado</span>, <span data-say=\"anoche\">anoche</span></td></tr>\n              <tr><td><strong>IMPERFECT</strong> — habit, description, ongoing</td><td><span data-say=\"normalmente\">normalmente</span>, <span data-say=\"todos los días\">todos los días</span>, <span data-say=\"de pequeño\">de pequeño</span>, <span data-say=\"mientras\">mientras</span></td></tr>\n            </table>\n            <p>The two often combine: <span data-say=\"Mientras yo cocinaba, mi hermano llegó a casa.\">Mientras yo cocinaba, mi hermano llegó a casa.</span> — <em>While I was cooking (ongoing, imperfect), my brother arrived (interrupting event, preterite).</em></p>\n            <p>Irregular imperfects: <span data-say=\"ser\">ser</span> → <span data-say=\"era\">era</span>; <span data-say=\"ir\">ir</span> → <span data-say=\"iba\">iba</span>; <span data-say=\"ver\">ver</span> → <span data-say=\"veía\">veía</span>.</p>", "question": "In ''Mientras cocinaba, mi hermano llegó'', why is ''llegó'' in the preterite?", "options": ["it is the single event that interrupted the ongoing action", "every verb that comes after the word ''mientras'' must always be preterite too", "''llegó'' describes a repeated daily habit", "the whole sentence is describing the future"]}'::jsonb, '{"answer": 0, "explain": "''cocinaba'' (imperfect) sets the ongoing background; ''llegó'' (preterite) is the single completed event that broke in."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:373f1e34', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "Higher: the perfect tense", "reading": "<p><span class=\"tier-h\">H</span> The perfect tense (<span data-say=\"el pretérito perfecto\">el pretérito perfecto</span>) links the past to NOW — recent past or experience, with no definite time marker like ''ayer''.</p>\n            <p>Form: <strong>haber</strong> + past participle.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>he</td><td><span data-say=\"he hablado\">he hablado</span></td><td>hemos</td><td>hemos comido</td></tr>\n              <tr><td>has</td><td>has vivido</td><td>habéis</td><td>habéis hecho</td></tr>\n              <tr><td>ha</td><td><span data-say=\"ha comido\">ha comido</span></td><td>han</td><td>han ido</td></tr>\n            </table>\n            <p>Irregular participles: <span data-say=\"hecho\">hecho</span> (hacer), visto (ver), escrito (escribir).</p>\n            <p>Example: <span data-say=\"Nunca he comido paella.\">Nunca he comido paella.</span> — <em>I have never eaten paella.</em></p>", "question": "How is the perfect tense formed?", "options": ["haber (he/has/ha…) + past participle", "the preterite stem plus the ending -aba", "estar + a gerund ending in -ando/-iendo", "the plain infinitive with no changes"]}'::jsonb, '{"answer": 0, "explain": "Perfect = present of haber + past participle: he comido, ha hecho. estar+gerund is the continuous; -aba builds the imperfect."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:2fd22e65', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "What about the ''tú'' and other imperfect forms of tricky verbs?", "reading": "<p>So far you''ve mostly seen <strong>yo/él</strong> imperfect forms. Listening and speaking tasks often need <strong>tú</strong> too — asking or telling someone what THEY used to do.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"ser\">ser</span></td><td><span data-say=\"era\">era</span> (yo/él)</td><td><span data-say=\"eras\">eras</span> (tú)</td></tr>\n              <tr><td><span data-say=\"ir\">ir</span></td><td><span data-say=\"iba\">iba</span> (yo/él)</td><td><span data-say=\"ibas\">ibas</span> (tú)</td></tr>\n              <tr><td><span data-say=\"ver\">ver</span></td><td><span data-say=\"veía\">veía</span> (yo/él)</td><td><span data-say=\"veías\">veías</span> (tú)</td></tr>\n              <tr><td><span data-say=\"tener\">tener</span></td><td><span data-say=\"tenía\">tenía</span> (yo/él)</td><td><span data-say=\"tenías\">tenías</span> (tú)</td></tr>\n              <tr><td><span data-say=\"estar\">estar</span></td><td>estaba (yo/él)</td><td><span data-say=\"estabas\">estabas</span> (tú)</td></tr>\n            </table>\n            <p><strong>tener</strong> and <strong>estar</strong> are regular in the imperfect — they just add -ía/-ías or -aba/-abas to the stem, unlike ser/ir/ver which change their stem. Example: <span data-say=\"Cuando eras pequeño, ¿tenías miedo de la oscuridad?\">Cuando eras pequeño, ¿tenías miedo de la oscuridad?</span> — <em>When you were little, were you afraid of the dark?</em></p>\n            <p>Another: <span data-say=\"Yo estaba en casa, pero tú estabas en el colegio.\">Yo estaba en casa, pero tú estabas en el colegio.</span> — <em>I was at home, but you were at school.</em></p>", "question": "What is the ''tú'' imperfect form of ''tener''?", "options": ["tenías", "tuviste", "tenía", "tienes"]}'::jsonb, '{"answer": 0, "explain": "tener is regular in the imperfect: tenía (yo/él), tenías (tú). ''tuviste'' is the preterite tú form; ''tienes'' is present."}'::jsonb),
('spanish:g-4-talking-about-the-past:learn:0cce3a41', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'learn', 'mcq', 1, '{"readingTitle": "How does ''dar'' behave in the preterite?", "reading": "<p><span data-say=\"dar\">dar</span> looks like a regular -AR verb, but in the preterite it borrows the -ER/-IR endings — and with NO written accents at all.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td>yo</td><td>di</td><td>nosotros/as</td><td><span data-say=\"dimos\">dimos</span></td></tr>\n              <tr><td>tú</td><td><span data-say=\"diste\">diste</span></td><td>vosotros/as</td><td><span data-say=\"disteis\">disteis</span></td></tr>\n              <tr><td>él/ella/usted</td><td><span data-say=\"dio\">dio</span></td><td>ellos/ellas/ustedes</td><td><span data-say=\"dieron\">dieron</span></td></tr>\n            </table>\n            <p>Example: <span data-say=\"Mi madre me dio un regalo y mis amigos me dieron una tarjeta.\">Mi madre me dio un regalo y mis amigos me dieron una tarjeta.</span> — <em>My mum gave me a present and my friends gave me a card.</em></p>", "question": "Which preterite ending pattern does ''dar'' follow?", "options": ["the -ER/-IR endings, but with no written accents", "the regular -AR endings, with accents on yo and él", "the same imperfect endings as hablar (-aba)", "no ending at all — dar stays the same in the past"]}'::jsonb, '{"answer": 0, "explain": "dar is -AR but takes -ER/-IR preterite endings without accents: di, diste, dio, dimos, disteis, dieron."}'::jsonb),
('spanish:g-4-talking-about-the-past:misc:56a6cd18', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Ayer jugaba al fútbol con mis amigos.</p><p><strong>✅ The correct idea:</strong> Ayer jugué al fútbol con mis amigos.</p>", "question": "Why is ''Ayer jugaba…'' wrong here?", "options": ["''ayer'' signals a single finished event, so it needs the preterite", "''jugaba'' is spelt correctly but carries an accent mark it should not have", "''jugar'' cannot be used with ''ayer'' at all", "the sentence should be in the future tense instead"]}'::jsonb, '{"answer": 0, "explain": "''ayer'' = a one-off, completed action → preterite (jugué), not the imperfect (jugaba), which suits habits."}'::jsonb),
('spanish:g-4-talking-about-the-past:misc:8289a69d', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Cuando era niño, jugué en el parque todos los días.</p><p><strong>✅ The correct idea:</strong> Cuando era niño, jugaba en el parque todos los días.</p>", "question": "Why is ''jugué…todos los días'' wrong here?", "options": ["''todos los días'' describes a repeated habit, needing the imperfect", "''todos los días'' can only ever be used together with the present tense, never the past", "''todos los días'' can only pair with the perfect tense", "the sentence needs a reflexive pronoun instead"]}'::jsonb, '{"answer": 0, "explain": "''todos los días'' signals a repeated childhood habit → imperfect (jugaba), not the preterite (jugué), which suits one-off events."}'::jsonb),
('spanish:g-4-talking-about-the-past:misc:e1c2d664', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Yo hací los deberes ayer.</p><p><strong>✅ The correct idea:</strong> Yo hice los deberes ayer.</p>", "question": "What is wrong with ''hací''?", "options": ["hacer''s irregular preterite stem is ''hic-'', giving ''hice''", "the ending ''-í'' used here is actually the completely correct and standard ending for hacer", "''hací'' is the correct imperfect form of hacer", "the accent mark has simply been left off ''hací''"]}'::jsonb, '{"answer": 0, "explain": "hacer is irregular in the preterite: hice, hiciste, hizo… There is no form ''hací'' — the stem changes to hic-."}'::jsonb),
('spanish:g-4-talking-about-the-past:misc:e6037db6', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Nunca comí paella.</p><p><strong>✅ The correct idea:</strong> Nunca he comido paella.</p>", "question": "Why does ''I have never eaten paella'' need the perfect, not the preterite?", "options": ["there is no definite past time marker, so the perfect links it to now", "''nunca'' can only ever be correctly followed by the imperfect tense in Spanish grammar", "''comí'' is actually spelt incorrectly in that sentence", "the preterite cannot be used with any negative word"]}'::jsonb, '{"answer": 0, "explain": "With no time marker like ''ayer'', an experience ''up to now'' takes the perfect: Nunca he comido paella."}'::jsonb),
('spanish:g-4-talking-about-the-past:misc:e891184c', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mientras cociné, mi hermano llegaba a casa.</p><p><strong>✅ The correct idea:</strong> Mientras cocinaba, mi hermano llegó a casa.</p>", "question": "Which verb should be the ongoing background action, and which the interrupting event?", "options": ["cocinaba is the ongoing background; llegó is the single interrupting event", "cociné is the ongoing background action here, while llegaba is meant to be the interrupting event", "both verbs must be in the preterite in this sentence", "both verbs must be in the imperfect in this sentence"]}'::jsonb, '{"answer": 0, "explain": "The wrong version swaps the tenses round: the ongoing action (cooking) needs the imperfect, and the single event that interrupts it (arriving) needs the preterite."}'::jsonb),
('spanish:g-4-talking-about-the-past:tips:015cd94c', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Listening for tense endings", "reading": "Preterite and imperfect verbs often differ by a single sound. Listen for the stressed final vowel: -é/-ó (preterite: hablé, habló) vs -aba/-ía (imperfect: hablaba, comía). That one sound changes whether it was a finished event or a habit.", "question": "You hear the ending ''-aba'' on a verb. What does that most likely signal?", "options": ["an imperfect form describing a habit or description", "a preterite form that is describing one single finished action in the past", "a command telling someone to do something", "the perfect tense describing an experience"]}'::jsonb, '{"answer": 0, "explain": "-aba is the -AR imperfect ending (hablaba, jugaba) — habits, descriptions, ongoing past actions."}'::jsonb),
('spanish:g-4-talking-about-the-past:tips:e8bf3329', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3 — Reading: spot the accent", "reading": "A missing or misread accent changes the tense entirely: ''hablo'' (I speak, present) vs ''habló'' (he/she spoke, preterite); ''hable'' (subjunctive) vs ''hablé'' (I spoke, preterite). Always check who is doing the action before you translate.", "question": "What is the key difference between ''hablo'' and ''habló'' in a reading text?", "options": ["''hablo'' is present tense (I), ''habló'' is preterite (he/she)", "they are simply two different but interchangeable spellings of the exact same word", "''habló'' is always the correct spelling to use", "there is no real difference in meaning between them"]}'::jsonb, '{"answer": 0, "explain": "The accent moves the stress and changes both tense and subject: hablo = I speak (now); habló = he/she spoke (finished)."}'::jsonb),
('spanish:g-4-talking-about-the-past:tips:5f2971d6', 'spanish', 'spanish:g-4-talking-about-the-past', 'G.4 Talking About the Past', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Writing: mix your past tenses", "reading": "Top-band answers combine tenses naturally: a preterite for a single trip, an imperfect for a childhood habit, and (Higher) a perfect for an experience with no date. Example: ''El año pasado fui a España. Cuando era niño, iba todos los veranos. Nunca he visitado Barcelona.''", "question": "Which answer shows the widest and most accurate range of past tenses?", "options": ["El año pasado fui a España; de niño iba cada verano; nunca he visitado Barcelona", "Fui a España, fui a Francia, fui a Italia y también fui a Portugal el año pasado otra vez", "Voy a España todos los años porque me gusta mucho viajar", "España es un país muy bonito con playas y montañas"]}'::jsonb, '{"answer": 0, "explain": "It combines preterite (fui), imperfect (iba) and perfect (he visitado) accurately — range, not just length or repetition."}'::jsonb),
