('spanish:g-5-future-conditional-and-more-tenses:tips:855e8f1f', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Listening for tense endings", "reading": "Future and conditional endings sound very similar — the difference is often just one syllable: hablará (future, he will speak) vs hablaría (conditional, he would speak). Listen carefully for the extra ‘-í-’ sound that marks the conditional.", "question": "You hear ‘…comería…’ rather than ‘…comerá…’. What does the extra syllable tell you?", "options": ["it is the conditional (would eat), not the future (will eat)", "it is simply a longer, more formal way of saying the same thing", "nothing changes — they mean exactly the same", "it must be a reflexive verb"]}'::jsonb, '{"answer": 0, "explain": "The -ía sound is the conditional marker (would); -á alone is the future marker (will)."}'::jsonb),
('spanish:g-5-future-conditional-and-more-tenses:tips:0628352f', 'spanish', 'spanish:g-5-future-conditional-and-more-tenses', 'G.5 Future, Conditional and More Tenses', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3/4 — Grammar accuracy in reading and writing", "reading": "Examiners reward accurate irregular stems (tendré, not tenerá) and the little word ‘a’ after ir (voy a…, not voy…). Build a checklist before you submit any future/conditional sentence.", "question": "Which sentence would lose an accuracy mark?", "options": ["Voy estudiar mañana por la tarde.", "Voy a estudiar mañana por la tarde.", "Mañana voy a estudiar por la tarde.", "Por la tarde, voy a estudiar mañana."]}'::jsonb, '{"answer": 0, "explain": "‘Voy estudiar’ is missing the essential ‘a’ — ir a + infinitive."}'::jsonb),
